#include <iostream>
using namespace std;

bool contains(int num, int t) {
    while (num > 0) {
        if (num % 10 == t) {
            return true;
        }
        num /= 10;
    }
    return false;
}

int main() {
    int m, t;
    cin >> m >> t;

    int count = 0;
    int floor = 0;
    while (count < m) {
        floor++;
        if (!contains(floor, t)) {
            count++;
        }
    }

    cout << floor << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    for (int x = 0; x <= 20; x++) {  // 公鸡最多20只
        for (int y = 0; y <= 33; y++) {  // 母鸡最多33只
            int z = 100 - x - y;  // 小鸡数量
            if (z % 3 == 0 && 5 * x + 3 * y + z / 3 == 100) {
                cout << "公鸡: " << x << " 母鸡: " << y << " 小鸡: " << z << endl;
            }
        }
    }
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n, i;
    cin >> n >> i;

    int k = 1;
    while (true) {
        int fish = k * n + i;
        bool valid = true;

        for (int j = 1; j < n; j++) {
            fish = fish / (n - 1) * n + i;
            if (fish % (n - 1) != 0) {
                valid = false;
                break;
            }
        }

        if (valid) {
            cout << fish << endl;
            break;
        }
        k++;
    }
    return 0;
}
